(function(){
  var NW=1280,NH=720;
  function sf(){
    var f=document.getElementById('c3d-tour');if(!f)return;
    var w=f.parentElement,bar=w.querySelector('.c3d-bar'),bH=bar?bar.offsetHeight:44;
    var fs=w.classList.contains('c3d-fullscreen'),aW=fs?window.innerWidth:w.clientWidth;
    var sc=fs?Math.min(aW/NW,(window.innerHeight-bH)/NH):aW/NW;
    f.style.width=NW+'px';f.style.height=NH+'px';
    f.style.transform='scale('+sc+')';f.style.transformOrigin='top left';
    f.style.marginBottom=Math.round(NH*(sc-1))+'px';
    f.style.marginLeft=fs?Math.max(0,Math.round((aW-NW*sc)/2))+'px':'0';
  }
  function tfs(){
    var f=document.getElementById('c3d-tour'),w=f.parentElement,b=document.getElementById('c3d-tour-fs');
    var fs=w.classList.toggle('c3d-fullscreen');b.textContent=fs?'\u2715':'\u26F6';
    if(fs){window._c3dy=window.scrollY;document.body.style.overflow='hidden';}
    else{document.body.style.overflow='';window.scrollTo(0,window._c3dy||0);}
    sf();
  }
  sf();
  if(window._c3dR)window.removeEventListener('resize',window._c3dR);
  window._c3dR=sf;window.addEventListener('resize',sf);
  if(window._c3dK)document.removeEventListener('keydown',window._c3dK);
  window._c3dK=function(e){if(e.key==='Escape'){var f=document.getElementById('c3d-tour');if(f&&f.parentElement.classList.contains('c3d-fullscreen'))tfs();}};
  document.addEventListener('keydown',window._c3dK);
  document.getElementById('c3d-tour-fs').onclick=tfs;

})()

